        static void AskUsername()
        {
            bool containscomma = false;
            do
            {
                containscomma = false;
                Console.Clear();
                DrawMenuBox(W, 5, X, Y);
                Console.SetCursorPosition(X + 2, Y + 2);
                Console.Write("Enter Username (No Commas): ");
                PLAYERNAME = Console.ReadLine().ToUpper();
                if (PLAYERNAME == string.Empty)
                {
                    PLAYERNAME = "Untitled Adventurer 1".ToUpper();
                }
                for (int i = 0; i < PLAYERNAME.Length; i++)
                {
                    if (PLAYERNAME[i] == ',')
                    {
                        DrawMenuBox(W, 5, X, Y);
                        Console.SetCursorPosition(X + 2, Y + 2);
                        Console.Write("That username contains character(s) that are not allowed!");
                        containscomma = true;
                        Thread.Sleep(1000);
                    }
                }
                MONSTERS[11] = $"{PLAYERNAME}.";
            } while (containscomma);
        }
        static void PlayMusic(string filename)
        {
            Assembly assembly = Assembly.GetExecutingAssembly();
            Stream audiostream = assembly.GetManifestResourceStream($"TheBookofMonsters.{filename}");
            SoundPlayer player = new SoundPlayer(audiostream);
            player.Play();
        }
        static void PlayMusicLooping(string filename)
        {
            Assembly assembly = Assembly.GetExecutingAssembly();
