            SoundPlayer player = new SoundPlayer(audiostream);
            player.PlayLooping();
        }
        static void ShowDeathMessage(string deathmessage)
        {
            TIMER.Stop();
            long elapsedmilliseconds = TIMER.ElapsedMilliseconds;
            TIME += (long)Math.Ceiling((double)elapsedmilliseconds / 60000);
            switch (MODE)
            {
                case "ADVENTURE":
                    ADVENTUREMODEDEATHS++;
                    break;
                case "ARCADE":
                    ARCADEMODEDEATHS++;
                    break;
            }
            Console.Clear();
            int[,] scene = LoadScene("");
            DisplayScene(scene, (CONSOLEWIDTH / 2) - 9, 0);
            Console.ResetColor();
            Console.SetCursorPosition(CONSOLEWIDTH / 2 - 5, 10);
            Console.Write("Game over!");
            Console.SetCursorPosition((CONSOLEWIDTH / 2) - (deathmessage.Length / 2), 12);
            Console.Write(deathmessage);
            Thread.Sleep(1000);
            Console.SetCursorPosition((CONSOLEWIDTH / 2) - ("Press any key to return to the Main Menu.".Length / 2), CONSOLEHEIGHT / 2);
            Console.ForegroundColor = ConsoleColor.White;
            Console.Write("Press any key to return to the Main Menu.");
            Console.ReadKey();
            PlayMusic("Click.wav");
            switch (MODE)
            {
                case "ADENTURE":
                    throw new AdventureModeDeath();
                case "ARCADE":
                    throw new ArcadeModeDeath();
            }
        }
        static void DrawStarryBackground(int stars, int exceptx1, int excepty1, int exceptx2, int excepty2)
        {
            int x;
            int y;
            Console.SetCursorPosition(0, 0);
            for (int i = 0; i < stars; i++)
            {
                x = rng.Next(0, CONSOLEWIDTH);
                y = rng.Next(0, CONSOLEHEIGHT);
                if (rng.Next(0, 2) == 0)
                {
                    Console.ForegroundColor = ConsoleColor.White;
                }
                else
                {
                    Console.ForegroundColor = ConsoleColor.Gray;
                }
                if (x >= exceptx1 && x <= exceptx2 && x >= excepty1 && x <= excepty2)
                {
                    continue;
                }
                Console.SetCursorPosition(x, y);
                if (rng.Next(0, 2) == 0)
                {
                    Console.Write('+');
                }
                else
                {
                    Console.Write('.');
                }

            }
        }
        static int[,] LoadScene(string scenecode)
        {
            string[] rows = scenecode.Split('y');
            int height = 0;
            int width = 0;

            for (int i = 0; i < rows.Length; i++)
            {
                if (rows[i] != "")
                {
                    height++;
                    string[] temp = rows[i].Split('x');
                    int count = 0;
                    for (int j = 0; j < temp.Length; j++)
                    {
                        if (temp[j] != "") count++;
                    }
                    if (count > width)
                    {
                        width = count;
                    }
                }
            }

            int[,] scene = new int[width, height];
            int y = 0;

            for (int i = 0; i < rows.Length; i++)
            {
                if (rows[i] == "") continue;

                string[] parts = rows[i].Split('x');
                int x = 0;
                for (int j = 0; j < parts.Length; j++)
                {
                    if (parts[j] == "") continue;

                    int num = 0;
                    try
                    {
                        num = int.Parse(parts[j]);
                    }
                    catch
                    {
                        num = 0;
                    }

                    scene[x, y] = num;
                    x++;
                }
                y++;
            }

            return scene;
        }
        static void DisplayScene(int[,] scene, int pos1, int pos2)
        {
            try
            {
                Console.SetCursorPosition(pos1, pos2);
                for (int y = 0; y < scene.GetLength(1); y++)
                {
                    for (int x = 0; x < scene.GetLength(0); x++)
                    {
                        Console.ForegroundColor = (ConsoleColor)scene[x, y];
                        Console.Write("██");
                    }
                    Console.SetCursorPosition(pos1, pos2 + y + 1);
                }
            }
            catch (ArgumentOutOfRangeException)
            {

            }
        }
        static void FadeOutScene(int[,] scene, int pos1, int pos2)
        {
            char[] characters = { '█', '▓', '▒', '░', ' ' };
            for (int i = 0; i < 5; i++)
            {
                try
                {
                    Console.SetCursorPosition(pos1, pos2);
                    for (int y = 0; y < scene.GetLength(1); y++)
                    {
                        for (int x = 0; x < scene.GetLength(0); x++)
                        {
                            Console.ForegroundColor = (ConsoleColor)scene[x, y];
                            Console.Write($"{characters[i]}{characters[i]}");
                        }
                        Console.SetCursorPosition(pos1, pos2 + y + 1);
                    }
                }
                catch (ArgumentOutOfRangeException)
                {

                }
                Thread.Sleep(50);
            }
        }
        static void FadeInScene(int[,] scene, int pos1, int pos2)
        {
            char[] characters = { '█', '▓', '▒', '░', ' ' };
            for (int i = 4; i >= 0; i--)
            {
                try
                {
                    Console.SetCursorPosition(pos1, pos2);
                    for (int y = 0; y < scene.GetLength(1); y++)
                    {
                        for (int x = 0; x < scene.GetLength(0); x++)
                        {
                            Console.ForegroundColor = (ConsoleColor)scene[x, y];
                            Console.Write($"{characters[i]}{characters[i]}");
                        }
                        Console.SetCursorPosition(pos1, pos2 + y + 1);
                    }
                }
                catch (ArgumentOutOfRangeException)
                {

                }

                Thread.Sleep(50);
            }
        }
        static void DisplayDialogue(string dialogue, int boxx, int boxy, int boxwidth, int boxheight)
        {
            DrawMenuBox(boxwidth, boxheight, boxx, boxy);
            int dialoguelength = dialogue.Length;
            int x = boxx + 2;
            int y = boxy + 1;
            bool skip = false;
            bool showprompt = true;
            for (int i = 0; i < dialoguelength; i++)
            {
                if (Console.KeyAvailable)
                {
                    var key = Console.ReadKey(true);
                    if (key.Key == ConsoleKey.X)
                    {
                        skip = true;
                        DIALOGUESSKIPPED++;
                    }
                }
                Console.SetCursorPosition(x, y);
                Console.Write(dialogue[i]);
                if ((i + 1) % (boxwidth - 4) == 0)
                {
                    y++;
                    x = boxx + 2;
                }
                else
                {
                    x++;
                }
                Console.SetCursorPosition(boxx + 2, boxy + boxheight - 2);
                Console.ForegroundColor = showprompt ? ConsoleColor.Yellow : ConsoleColor.DarkYellow;
                Console.Write("Press X to skip");
                Console.ResetColor();
                showprompt = !showprompt;
                if (skip == false)
                {
                    Thread.Sleep(3);
                }
            }
            Console.SetCursorPosition(boxx + 2, boxy + boxheight - 2);
            Console.ForegroundColor = ConsoleColor.Yellow;
            Console.Write("Press X to skip");
            Console.ResetColor();
            Thread.Sleep(500);
        }
