        static int HowClose(int x, int barwidth, int boxx)
        {
            double temp = Math.Abs(x - (barwidth + boxx) / 2) / 10;
            temp = Math.Truncate(temp);
            return (int)temp;
        }
        static void ReactionMenuConsoleColour(int barwidth, int i)
        {
            double temp = (Math.Abs(i - (barwidth / 2)) / 3);
            temp = Math.Round(temp);
            Console.ForegroundColor = ConsoleColor.DarkRed;
            switch (temp)
            {
                default:
                    Console.ForegroundColor = ConsoleColor.DarkRed;
                    break;
                case 6:
                    Console.ForegroundColor = ConsoleColor.Red;
                    break;
                case 5:
                    Console.ForegroundColor = ConsoleColor.Red;
                    break;
                case 4:
                    Console.ForegroundColor = ConsoleColor.Red;
                    break;
