        static int DisplayReactionMenu(string dialogue, int boxx, int boxy, int boxwidth, int boxheight, int speed)
        {
            int i;
            int choice = 0;
            DrawMenuBox(boxwidth, boxheight, boxx, boxy);
            Console.SetCursorPosition(boxx + 2, boxy + 1);
            Console.WriteLine(dialogue);
            int menuTop = Console.CursorTop + 1;
            int menuLeft = boxx + 3;
            int prompty = boxy + boxheight - 2;
            int barwidth = boxwidth - 4;
            int x = boxx + 2;
            bool direction = false;
            string[,] options = new string[0, 0];
            int lastx = x;

            DrawMenu(choice, options, menuTop, menuLeft, boxwidth - 4);
            Console.SetCursorPosition(boxx + 2, prompty - 1);
            for (i = 0; i < barwidth; i++)
            {
                ReactionMenuConsoleColour(barwidth, i);
                Console.Write("━");
            }
            do
            {
                lastx = x;
                if (direction)
                {
                    x++;
                }
                else
                {
                    x--;
                }
                if (x <= boxx + 2)
                {
                    direction = true;
                }
                else if (x >= boxwidth + boxx - 3)
                {
                    direction = false;
                }
                Console.SetCursorPosition(x, prompty - 2);
                Console.ForegroundColor = ConsoleColor.DarkYellow;
                Console.Write("∇");
                Console.SetCursorPosition(x, prompty);
                Console.Write("Δ");
                Console.SetCursorPosition(boxx + 2, prompty - 1);
                if (Console.KeyAvailable)
                {
                    return HowClose(x, barwidth, boxx);
                }
                Thread.Sleep(speed);
                Console.SetCursorPosition(lastx, prompty - 2);
                Console.Write(' ');
                Console.SetCursorPosition(lastx, prompty);
                Console.Write(' ');
                Console.SetCursorPosition(0, 0);
            } while (true);
        }
        static int DisplayTimedMenu(string[,] options, string dialogue, int boxx, int boxy, int boxwidth, int boxheight, double timer)
        {
            int choice = 0;
            DrawMenuBox(boxwidth, boxheight, boxx, boxy);
            Console.SetCursorPosition(boxx + 2, boxy + 1);
            Console.WriteLine(dialogue);
            int menuTop = Console.CursorTop + 1;
            int menuLeft = boxx + 3;
            int prompty = boxy + boxheight - 2;
            double progressbar = boxwidth - 4;

            DrawMenu(choice, options, menuTop, menuLeft, boxwidth - 4);
            Stopwatch stopwatch = Stopwatch.StartNew();
            TimeSpan maxTime = TimeSpan.FromSeconds(timer);
            do
            {
                TimeSpan timeLeft = maxTime - stopwatch.Elapsed;
                if (timeLeft <= TimeSpan.Zero)
                {
                    return -1;
                }
                Console.SetCursorPosition(boxx + 2, prompty - 1);
                for (int i = 0; i < (int)progressbar; i++)
                {
                    Console.Write("  ");
                }
                Console.SetCursorPosition(boxwidth + boxx - 1, prompty - 1);
                Console.ForegroundColor = ConsoleColor.White;
                Console.Write("┃");
                Console.SetCursorPosition(boxx, prompty);
                Console.Write("┃");
                progressbar = (timeLeft.TotalMilliseconds / maxTime.TotalMilliseconds) * (boxwidth - 4);
                Console.SetCursorPosition(boxx + 2, prompty - 1);
                for (int i = 0; i < (int)progressbar; i++)
                {
                    Console.ForegroundColor = (timeLeft.TotalSeconds < 3) ? ConsoleColor.Red : ConsoleColor.Yellow;
                    Console.Write("━");
                    Console.ResetColor();
                }
                Console.SetCursorPosition(boxx + 2, prompty);
                Console.ForegroundColor = (timeLeft.TotalSeconds < 3) ? ConsoleColor.Red : ConsoleColor.Yellow;
                Console.Write($"Time remaining: {timeLeft.TotalMilliseconds / 1000:0.00}");
                Console.ResetColor();
                if (Console.KeyAvailable)
                {
                    ConsoleKeyInfo key = Console.ReadKey(true);
                    switch (key.Key)
                    {
                        case ConsoleKey.W:
                            choice = (choice - 1 + options.GetLength(0)) % options.GetLength(0);
                            DrawMenu(choice, options, menuTop, menuLeft, boxwidth - 4);
                            break;
                        case ConsoleKey.S:
                            choice = (choice + 1) % options.GetLength(0);
                            DrawMenu(choice, options, menuTop, menuLeft, boxwidth - 4);
                            break;
                        case ConsoleKey.Enter:
                            return choice;
                    }
                }
                Thread.Sleep(50);
            } while (true);
        }
        static int DisplayMenu(string[,] options, string dialogue, int boxx, int boxy, int boxwidth, int boxheight)
        {
            int choice = 0;
            bool running = true;
            Console.ForegroundColor = ConsoleColor.White;
            DrawMenuBox(boxwidth, boxheight, boxx, boxy);
            Console.SetCursorPosition(boxx + 2, boxy + 1);
            Console.WriteLine(dialogue);
            int menuTop = Console.CursorTop + 1;
            int menuLeft = boxx + 3;

            DrawMenu(choice, options, menuTop, menuLeft, boxwidth - 4);

            do
            {
                ConsoleKeyInfo key = Console.ReadKey(true);
                switch (key.Key)
                {
                    case ConsoleKey.W:
                        choice = (choice - 1 + options.GetLength(0)) % options.GetLength(0);
                        DrawMenu(choice, options, menuTop, menuLeft, boxwidth - 4);
                        break;

                    case ConsoleKey.S:
                        choice = (choice + 1) % options.GetLength(0);
                        DrawMenu(choice, options, menuTop, menuLeft, boxwidth - 4);
                        break;

                    case ConsoleKey.Enter:
                        return choice;

                    case ConsoleKey.Escape:
                        running = false;
                        return -1;
                }
            } while (running);

            return -1;
        }
