        static void DisplayBossBar(string text, int health, int maxhealth, int y)
        {
            int barlength = 100;
            int barfilled = (int)((double)health / maxhealth * barlength);
            double colour = (double)health / (double)maxhealth;
            Console.ForegroundColor = ConsoleColor.White;
            Console.ForegroundColor = ConsoleColor.DarkYellow;
            if (colour <= 0.5 && colour > 0.25)
            {
                Console.ForegroundColor = ConsoleColor.Red;
            }
            else if (colour <= 0.25)
            {
                Console.ForegroundColor = ConsoleColor.DarkRed;
            }
            try
            {
                Console.SetCursorPosition(X, y + 1);
                Console.Write("[");
                Console.Write(new string('█', barfilled));
                Console.ForegroundColor = ConsoleColor.DarkGray;
                Console.Write(new string('-', barlength - barfilled));
                Console.ForegroundColor = ConsoleColor.DarkYellow;
                if (colour <= 0.5 && colour > 0.25)
                {
                    Console.ForegroundColor = ConsoleColor.Red;
                }
                else if (colour <= 0.25)
                {
                    Console.ForegroundColor = ConsoleColor.DarkRed;
                }
                Console.Write("]");
                Console.SetCursorPosition(50 + X - ($"[{health}/{maxhealth}]".ToString()).Length / 2, y + 2);
                Console.Write($"[{health}/{maxhealth}]");
                Console.SetCursorPosition(50 + X - text.Length / 2, y);
                Console.ForegroundColor = ConsoleColor.White;
                Console.Write(text);
                Console.SetCursorPosition(X + W - 2, y);
            }
            catch (ArgumentOutOfRangeException)
            {
            }
        }
