        static void DrawMenuBox(int width, int height, int x, int y)
        {
            Console.SetCursorPosition(x, y);
            Console.Write("┏" + new string('━', width - 2) + "┓");
            for (int i = 1; i < height - 1; i++)
            {
                Console.SetCursorPosition(x, y + i);
                Console.Write("┃" + new string(' ', width - 2) + "┃");
            }
            Console.SetCursorPosition(x, y + height - 1);
            Console.Write("┗" + new string('━', width - 2) + "┛");

            Console.ResetColor();
        }
        static void DrawMenu(int choice, string[,] options, int top, int left, int width)
        {
            int numitems = options.GetLength(0);
            int numprops = options.GetLength(1);

            for (int i = 0; i < numitems; i++)
            {
                Console.SetCursorPosition(left, top + i);
                Console.Write(new string(' ', width - 2));
                Console.SetCursorPosition(left, top + i);
                if (i == choice)
                {
                    Console.ForegroundColor = ConsoleColor.Cyan;
                    Console.Write("> ");
                }
                else
                {
                    Console.Write("  ");
                }

                for (int j = 0; j < numprops; j++)
                    Console.Write($"{options[i, j]} ");
                Console.ResetColor();
            }
        }
        static void DVDScreenSaver(int boxx, int boxy, int boxwidth, int boxheight, int time)
        {
            PlayMusicLooping("Elevator.wav");
            int x = boxx + boxwidth / 2;
            int y = boxy + boxheight / 2;
            Console.ForegroundColor = ConsoleColor.White;
            DrawMenuBox(boxwidth, boxheight, boxx, boxy);
            DrawMenuBox(boxwidth / 2, 3, boxx + boxwidth / 4, boxy - 2);
            Console.SetCursorPosition(boxx + boxwidth / 4 + 1, boxy - 1);
            Console.Write("           Procrastination Simulator");
            char dirx = '+';
            char diry = '+';
            int lastx = x;
            int lasty = y;
            Console.ForegroundColor = ConsoleColor.White;
            Stopwatch stopwatch = Stopwatch.StartNew();
            TimeSpan maxtime = TimeSpan.FromSeconds(time);
            while (true)
            {
                TimeSpan timeLeft = maxtime - stopwatch.Elapsed;
                if (timeLeft <= TimeSpan.Zero)
                {
                    break;
                }
                lastx = x;
                lasty = y;
                Console.SetCursorPosition(x, y);
                Console.ForegroundColor = ConsoleColor.Red;
                Console.Write("●");
                if (x >= boxwidth - 2 + boxx)
                {
                    dirx = '-';
                }
                else if (x <= 1 + boxx)
                {
                    dirx = '+';
                }
                if (y >= boxheight - 2 + boxy)
                {
                    diry = '-';
                }
                else if (y <= 1 + boxy)
                {
                    diry = '+';
                }

                switch (dirx)
                {
                    case '+':
                        x++;
                        break;
                    case '-':
                        x--;
                        break;
                }
                switch (diry)
                {
                    case '+':
                        y++;
                        break;
                    case '-':
                        y--;
                        break;
                }
                System.Threading.Thread.Sleep(50);
                Console.SetCursorPosition(lastx, lasty);
                Console.Write(" ");
            }
        }
        static int BouncyBulletGame(int boxx, int boxy, int boxwidth, int boxheight, int time)
        {
            DrawMenuBox(boxwidth, boxheight, boxx, boxy);
            int x = boxx + 5;
            int y = boxheight / 2 + boxy;
            double G = 0.5;
            double speedy = 0;
            int lasty = y;
            int blastery = 0;
            int blasterx = boxx + boxwidth - 2;
            int lastblasterx = blasterx;
            bool blaster = false;
            int lasery = 0;
            int laserx = boxx + boxwidth - 2;
            bool laser = false;
            int lasertime = 0;
            DisplayMinigameDescription("Bounce to avoid bullets!", boxy + boxheight / 2 - 1);
            for (int i = 3; i > 0; i--)
            {
                Console.SetCursorPosition(boxx + boxwidth / 2 - 1, boxy + boxheight / 2 - 1);
                Console.Write(i);
                Thread.Sleep(1000);
            }
            Console.SetCursorPosition(boxx + boxwidth / 2 - 1, boxy + boxheight / 2 - 1);
            Console.Write(' ');
            Stopwatch stopwatch = Stopwatch.StartNew();
            TimeSpan maxtime = TimeSpan.FromSeconds(time);
            Console.SetCursorPosition(boxx + boxwidth / 2 - 1, boxy + boxheight / 2 - 1);
            Console.Write(' ');
            while (true)
            {
                TimeSpan timeLeft = maxtime - stopwatch.Elapsed;
                if (timeLeft <= TimeSpan.Zero)
                {
                    return 0;
                }
                Console.ForegroundColor = ConsoleColor.White;
                Console.SetCursorPosition(boxx + 3, boxy + 2);
                Console.Write($"Time remaining: {timeLeft.TotalMilliseconds / 1000:0.00}");
                if (y <= boxy + 1)
                {
                    return -1;
                }
                if (y >= boxy + boxheight)
                {
                    return -1;
                }
                if (blaster && blastery == y && blasterx <= x && blasterx >= x - 2)
                {
                    return -1;
                }
                if (laser && lasertime < 1000 && lasertime > 0 && y == lasery)
                {
                    return -1;
                }
                if (rng.NextDouble() < 0.1 && laser == false)
                {
                    lasery = rng.Next(boxy, boxy + boxheight - 1);
                    laserx = boxx + boxwidth - 2;
                    laser = true;
                    lasertime = 2000;
                }
                if (laser)
                {
                    Console.ForegroundColor = ConsoleColor.Red;
                    switch (lasertime)
                    {
                        case 2000:
                            Console.SetCursorPosition(laserx - 1, lasery);
                            Console.Write("⚠");
                            break;
                        case 1000:
                            Console.SetCursorPosition(laserx, lasery);
                            for (int i = 0; i < boxwidth - 1; i++)
                            {
                                Console.Write("━");
                                Console.SetCursorPosition(laserx - i, lasery);
                            }
                            break;
                        case 0:
                            laserx = boxx + boxwidth - 2;
                            Console.SetCursorPosition(laserx, lasery);
                            for (int i = 0; i < boxwidth - 1; i++)
                            {
                                Console.Write(" ");
                                Console.SetCursorPosition(laserx - i, lasery);
                            }
                            laser = false;
                            break;
                    }
                }
                lasertime -= 20;
                if (rng.NextDouble() < 0.1 && blaster == false)
                {
                    blastery = rng.Next(boxy, boxy + boxheight - 1);
                    blasterx = boxx + boxwidth - 2;
                    blaster = true;
                }
                if (blaster)
                {
                    lastblasterx = blasterx;
                    Console.SetCursorPosition(blasterx, blastery);
                    Console.ForegroundColor = ConsoleColor.Red;
                    Console.Write("━");
                    blasterx -= 2;
                    if (blasterx < boxx + 2)
                    {
                        blaster = false;
                    }
                }
                Console.SetCursorPosition(x, y);
                Console.ForegroundColor = ConsoleColor.DarkYellow;
                Console.Write("●");
                lasty = y;
                speedy += G;
                y += (int)speedy;
                if (Console.KeyAvailable)
                {
                    var key = Console.ReadKey(true);
                    if (key.Key == ConsoleKey.Spacebar)
                    {
                        speedy = -2.15;
                    }
                }
                System.Threading.Thread.Sleep(50);
                Console.SetCursorPosition(x, lasty);
                Console.Write(" ");
                Console.SetCursorPosition(lastblasterx, blastery);
                Console.Write(" ");
            }
        }
        static int DinoGame(int boxx, int boxy, int boxwidth, int boxheight, int scrollspeed, int time)
        {
            DrawMenuBox(boxwidth, boxheight, boxx, boxy);
            const double JUMPSTRENGTH = 3.14;
            const double GRAVITY = 0.5;
            double speedy = 0;
            int y = boxy + boxheight - 2;
            int lasty = y;
            int enemyx = 0;
            int lastenemyx = enemyx;
            int enemyheight = 1;
            bool enemy = false;
            int enemy2x = enemyx;
            int lastenemy2x = enemy2x;
            int enemy2height = 1;
            bool enemy2 = false;
            DisplayMinigameDescription("Jump over the obstacles!", boxy + boxheight / 2 - 1);
            for (int i = 3; i > 0; i--)
            {
                Console.SetCursorPosition(boxx + boxwidth / 2 - 1, boxy + boxheight / 2 - 1);
                Console.Write(i);
                Thread.Sleep(1000);
            }
            Console.SetCursorPosition(boxx + boxwidth / 2 - 1, boxy + boxheight / 2 - 1);
            Console.Write(' ');
            Stopwatch stopwatch = Stopwatch.StartNew();
            TimeSpan maxtime = TimeSpan.FromSeconds(time);
            while (true)
            {
                lasty = y;
                lastenemyx = enemyx;
                lastenemy2x = enemy2x;
                TimeSpan timeLeft = maxtime - stopwatch.Elapsed;
                if (timeLeft <= TimeSpan.Zero)
                {
                    return 0;
                }
                Console.ForegroundColor = ConsoleColor.White;
                Console.SetCursorPosition(boxx + 3, boxy + 2);
                Console.Write($"Time remaining: {timeLeft.TotalMilliseconds / 1000:0.00}");
                for (int i = 0; i < enemyheight; i++)
                {
                    Console.SetCursorPosition(lastenemyx, boxy + boxheight - 2 - i);
                    Console.Write(" ");
                }
                Console.SetCursorPosition(enemy2x, boxy + boxheight - 1);
                Console.Write("━");
                for (int i = 0; i < enemy2height; i++)
                {
                    Console.SetCursorPosition(lastenemy2x, boxy + boxheight - 2 - i);
                    Console.Write(" ");
                }
                Console.SetCursorPosition(enemyx, boxy + boxheight - 1);
                Console.Write("━");
                if (Console.KeyAvailable)
                {
                    var key = Console.ReadKey(true);
                    if (key.Key == ConsoleKey.Spacebar && y >= boxy + boxheight - 2)
                    {
                        speedy = -JUMPSTRENGTH;
                    }
                }
                speedy += GRAVITY;
                y += (int)speedy;
                --enemyx;
                --enemy2x;
                if (enemy2x <= 0)
                {
                    enemy2x = 0;
                }
                if (y > boxy + boxheight - 2)
                {
                    y = boxy + boxheight - 2;
                    speedy = 0;
                }
                if (y < boxy + 1)
                {
                    y = boxy + 1;
                    speedy = 0;
                }
                if (enemyx <= boxx + 2)
                {
                    enemy = false;
                }
                if (!enemy)
                {
                    enemyx = boxx + boxwidth - 2;
                    enemyheight = rng.Next(1, 4);
                    enemy = true;
                }
                else
                {
                    Console.ForegroundColor = ConsoleColor.White;
                    for (int i = 0; i < enemyheight; i++)
                    {
                        Console.SetCursorPosition(enemyx, boxy + boxheight - 2 - i);
                        Console.Write("┃");
                    }
                    Console.SetCursorPosition(enemyx, boxy + boxheight - 1);
                    Console.Write("┻");
                }
                for (int i = 0; i < enemy2height; i++)
                {
                    if (enemy2x == boxx + 5 && y >= boxy + boxheight - 2 - i)
                    {
                        return -1;
                    }
                }
                if (enemy2x <= boxx + 2)
                {
                    enemy2 = false;
                }
                if (!enemy2 && enemyx < boxx + boxwidth - boxwidth / 2)
                {
                    enemy2x = boxx + boxwidth - 2;
                    enemy2height = rng.Next(2, 4);
                    enemy2 = true;
                }
                else
                {
                    Console.ForegroundColor = ConsoleColor.White;
                    for (int i = 0; i < enemy2height; i++)
                    {
                        Console.SetCursorPosition(enemy2x, boxy + boxheight - 2 - i);
