                lastenemy2x = enemy2x;
                TimeSpan timeLeft = maxtime - stopwatch.Elapsed;
                if (timeLeft <= TimeSpan.Zero)
                {
                    return 0;
                }
                Console.ForegroundColor = ConsoleColor.White;
                Console.SetCursorPosition(boxx + 3, boxy + 2);
                Console.Write($"Time remaining: {timeLeft.TotalMilliseconds / 1000:0.00}");
                for (int i = 0; i < enemyheight; i++)
                {
                    Console.SetCursorPosition(lastenemyx, boxy + boxheight - 2 - i);
                    Console.Write(" ");
                }
                Console.SetCursorPosition(enemyx, boxy + boxheight - 1);
                Console.Write("━");
                for (int i = 0; i < enemy2height; i++)
                {
                    Console.SetCursorPosition(enemy2x, boxy + i);
                    Console.Write(" ");
                }
                Console.SetCursorPosition(enemy2x, boxy);
                Console.Write("━");
                if (Console.KeyAvailable)
                {
                    var key = Console.ReadKey(intercept: true).Key;

                    switch (key)
                    {
                        case ConsoleKey.W:
                            y -= JUMPSTRENGTH;
                            break;
                        case ConsoleKey.S:
                            y += JUMPSTRENGTH;
                            break;
                        case ConsoleKey.D:
                            x += 1;
                            break;
                        case ConsoleKey.A:
                            x -= 1;
                            break;
                    }
                }
                --enemyx;
                --enemy2x;
                if (enemy2x <= 0)
                {
                    enemy2x = 0;
                }
                if (y > boxy + boxheight - 2)
                {
                    y = boxy + boxheight - 2;
                }
                if (y < boxy + 1)
                {
                    y = boxy + 1;
                }
                if (x <= boxx + 2)
                {
                    x = boxx + 2;
                }
                if (x >= boxx + boxwidth - 2)
                {
                    x = boxx + boxwidth - 2;
                }
                if (enemyx <= boxx + 2)
                {
                    enemy = false;
                }
                if (!enemy)
                {
                    enemyx = boxx + boxwidth - 2;
                    enemyheight = rng.Next(5, 10);
                    enemy = true;
                }
                else
                {
                    Console.ForegroundColor = ConsoleColor.White;
                    for (int i = 0; i < enemyheight; i++)
                    {
                        Console.SetCursorPosition(enemyx, boxy + boxheight - 2 - i);
                        Console.Write("┃");
                    }
                    Console.SetCursorPosition(enemyx, boxy + boxheight - 1);
                    Console.Write("┻");
                }
                if (enemy2x <= boxx + 2)
                {
                    enemy2 = false;
                }
                if (!enemy2 && enemyx < boxx + boxwidth - boxwidth / 2)
                {
                    enemy2x = boxx + boxwidth - 2;
                    enemy2height = rng.Next(5, 12);
                    enemy2 = true;
                }
                else
                {
                    Console.ForegroundColor = ConsoleColor.White;
                    for (int i = 0; i < enemy2height; i++)
                    {
                        Console.SetCursorPosition(enemy2x, boxy + i);
                        Console.Write("┃");
                    }
                    Console.SetCursorPosition(enemy2x, boxy);
                    Console.Write("┳");
                }
                for (int i = 0; i < enemy2height; i++)
                {
                    if (enemy2x == x && y == boxy + i)
                    {
                        return -1;
                    }
                }
                for (int i = 0; i < enemyheight; i++)
                {
                    if (enemyx == x && y >= boxy + boxheight - 2 - i)
                    {
                        return -1;
                    }
                }
                Console.ForegroundColor = ConsoleColor.DarkYellow;
                Console.SetCursorPosition(x, y);
                Console.Write("●");
                if (lasty != y || lastx != x)
                {
                    Console.SetCursorPosition(lastx, lasty);
                    Console.Write(" ");
                }
                System.Threading.Thread.Sleep(scrollspeed);
            }
        }
        static int BlasterDodgemsGame(int boxx, int boxy, int boxwidth, int boxheight, int time)
        {
            DrawMenuBox(boxheight * 2, boxheight, boxwidth / 2, boxy);
            int y = boxy + boxheight - 2;
            int lasty = y;
            int x = boxwidth / 2 + 1;
            int lastx = x;
            int lasery = 0;
            int laserx = boxx + boxwidth - 2;
            bool laser = false;
            int lasertime = 0;
            int verticallaserx = 0;
            int verticallasery = boxx + boxwidth - 2;
            bool verticallaser = false;
            int verticallasertime = 0;
            DisplayMinigameDescription("Dodge the blasters!", boxy + boxheight / 2 - 1);
            for (int i = 3; i > 0; i--)
            {
                Console.SetCursorPosition(boxx + boxwidth / 2 - 1, boxy + boxheight / 2 - 1);
                Console.Write(i);
                Thread.Sleep(1000);
            }
            Console.SetCursorPosition(boxx + boxwidth / 2 - 1, boxy + boxheight / 2 - 1);
            Console.Write(' ');
            Stopwatch stopwatch = Stopwatch.StartNew();
            TimeSpan maxtime = TimeSpan.FromSeconds(time);
            while (true)
            {
                lastx = x;
                lasty = y;
                TimeSpan timeLeft = maxtime - stopwatch.Elapsed;
                if (timeLeft <= TimeSpan.Zero)
                {
                    return 0;
                }
                Console.ForegroundColor = ConsoleColor.White;
                Console.SetCursorPosition(boxx + 3, boxy + 2);
                Console.Write($"Time remaining: {timeLeft.TotalMilliseconds / 1000:0.00}");
                if (Console.KeyAvailable)
                {
                    var key = Console.ReadKey(intercept: true).Key;

                    switch (key)
                    {
                        case ConsoleKey.W:
                            y -= 1;
                            break;
                        case ConsoleKey.S:
                            y += 1;
                            break;
                        case ConsoleKey.D:
                            x += 1;
                            break;
                        case ConsoleKey.A:
                            x -= 1;
                            break;
                    }
                }
                if (y > boxy + boxheight - 2)
                {
                    y = boxy + boxheight - 2;
                }
                if (y < boxy + 1)
                {
                    y = boxy + 1;
                }
                if (x <= boxwidth / 2 + 1)
                {
                    x = boxwidth / 2 + 1;
                }
                if (x >= boxheight * 2 + boxwidth / 2 - 2)
                {
                    x = boxheight * 2 + boxwidth / 2 - 2;
                }
                Console.ForegroundColor = ConsoleColor.DarkYellow;
                Console.SetCursorPosition(x, y);
                Console.Write("●");
                if (lasty != y || lastx != x)
                {
                    Console.SetCursorPosition(lastx, lasty);
                    Console.Write(" ");
                }
                if (rng.NextDouble() < 0.1 && !laser)
                {
                    lasery = y;
                    laserx = boxheight * 2 + boxwidth / 2 - 2;
                    laser = true;
                    lasertime = 2000;
                }
                if (laser)
                {
                    Console.ForegroundColor = ConsoleColor.Red;
                    switch (lasertime)
                    {
                        case 2000:
                            Console.SetCursorPosition(laserx - 1, lasery);
                            Console.Write("⚠");
                            break;

                        case 1000:
                            Console.SetCursorPosition(laserx, lasery);
                            for (int i = 0; i < boxheight * 2 - 1; i++)
                            {
                                Console.Write("━");
                                Console.SetCursorPosition(laserx - i, lasery);
                            }
                            break;

                        case 0:
                            Console.SetCursorPosition(laserx, lasery);
                            for (int i = 0; i < boxheight * 2 - 1; i++)
                            {
                                Console.Write(" ");
                                Console.SetCursorPosition(laserx - i, lasery);
                            }
                            laser = false;
                            break;
                    }
                }
                if (rng.NextDouble() < 0.1 && !verticallaser)
                {
                    verticallaserx = x;
                    verticallasery = boxy + boxheight;
                    verticallaser = true;
                    verticallasertime = 2000;
                }

                if (verticallaser)
                {
                    Console.ForegroundColor = ConsoleColor.Red;

                    switch (verticallasertime)
                    {
                        case 2000:
                            Console.SetCursorPosition(verticallaserx, boxy + 1);
                            Console.Write("⚠");
                            break;

                        case 1000:
                            for (int i = 1; i < boxheight - 1; i++)
                            {
                                Console.SetCursorPosition(verticallaserx, boxy + i);
                                if (laser && verticallaser && laserx == verticallaserx && lasery == boxy + i)
                                {
                                    Console.ForegroundColor = ConsoleColor.DarkRed;
                                    Console.Write("╋");
                                    Console.ForegroundColor = ConsoleColor.Red;
                                }
                                else
                                {
                                    Console.Write("┃");
                                }
                            }
                            break;

                        case 0:
                            for (int i = 1; i < boxheight - 1; i++)
                            {
                                Console.SetCursorPosition(verticallaserx, boxy + i);
                                Console.Write(" ");
                            }
                            verticallaser = false;
                            break;
                    }
                }
                lasertime -= 100;
                verticallasertime -= 100;
                if (laser && lasery == y && lasertime <= 1000)
                {
                    return -1;
                }
                if (verticallaser && verticallaserx == x && verticallasertime <= 1000)
                {
                    return -1;
                }
                System.Threading.Thread.Sleep(50);
                Console.SetCursorPosition(lastx, lasty);
                Console.Write(" ");
            }
        }
