        static void DisplayEpilogueBookOfMonsters(string[,] options, string dialogue, int boxx, int boxy, int boxwidth, int boxheight, bool state)
        {
            GenerateBookOfMonstersPage();
            int choice = 0;
            Console.ForegroundColor = ConsoleColor.White;
            DrawMenuBox(boxwidth, boxheight, boxx, boxy);
            Console.SetCursorPosition(boxx + 2, boxy + 1);
            Console.WriteLine(dialogue);
            int menutop = Console.CursorTop + 1;
            int menuleft = boxx + 3;
            DrawMenu(choice, options, menutop, menuleft, boxwidth - 4);
            Console.SetCursorPosition(boxx + 2, boxy + boxheight - 2);
            Console.SetCursorPosition(boxwidth + boxx - 11, boxy + boxheight - 2);
            Console.Write($"Page {BOOKOFMONSTERSPAGE + 1}/{Math.Ceiling((double)NUMBEROFENTRIESINBOOKOFMONSTERS / 6)}");
            for (int i = 12; i > 0; i--)
            {
                if (i % 2 == 0)
                {
                    Console.Clear();
                }
                DrawMenuBox(boxwidth, boxheight, boxx, boxy);
                DrawMenu(choice, options, menutop, menuleft, boxwidth - 4);
                Console.SetCursorPosition(boxwidth + boxx - 11, boxy + boxheight - 2);
                Console.Write($"Page {BOOKOFMONSTERSPAGE + 1}/{Math.Ceiling((double)NUMBEROFENTRIESINBOOKOFMONSTERS / 6)}");
                Console.SetCursorPosition(boxx + 2, boxy + 1);
                Console.WriteLine(dialogue);
                choice = (choice + 1) % options.GetLength(0);
                Thread.Sleep(i * 5);
            }
            for (int i = 0; i > -60; i--)
            {
                DrawMenuBox(boxwidth, boxheight, boxx, boxy);
                DrawMenu(choice, options, menutop, menuleft, boxwidth - 4);
                switch (state)
                {
                    case true:
                        AddEntryToBookOfMonsters("Guide", "Freed");
                        AddEntryToBookOfMonsters($"{PLAYERNAME}", "Freed");
                        break;
                    case false:
                        AddEntryToBookOfMonsters("Guide", "Freed");
                        AddEntryToBookOfMonsters($"{PLAYERNAME}", "Trapped");
                        break;
                }
                GenerateBookOfMonstersPage();
                Console.SetCursorPosition(boxx + 2, boxy + 1);
                Console.WriteLine(dialogue);
                if (i % 2 == 0)
                {
                    Console.Clear();
                }
                if (i % 6 == 0)
                {
                    BOOKOFMONSTERSPAGE++;
                }
                choice = (choice + 1) % options.GetLength(0);
                Console.SetCursorPosition(boxwidth + boxx - 11, boxy + boxheight - 2);
                Console.Write($"Page {BOOKOFMONSTERSPAGE + 1}/{Math.Ceiling((double)NUMBEROFENTRIESINBOOKOFMONSTERS / 6)}");
                Thread.Sleep(5);
            }
            Console.Clear();
        }
        static int DisplayBookOfMonstersMenu(string[,] options, string dialogue, int boxx, int boxy, int boxwidth, int boxheight)
        {
            GenerateBookOfMonstersPage();
            int choice = 0;
            bool running = true;
            Console.ForegroundColor = ConsoleColor.White;
            DrawMenuBox(boxwidth, boxheight, boxx, boxy);
            Console.SetCursorPosition(boxx + 2, boxy + 1);
            Console.WriteLine(dialogue);
            int menutop = Console.CursorTop + 1;
            int menuleft = boxx + 3;
            DrawMenu(choice, options, menutop, menuleft, boxwidth - 4);
            Console.SetCursorPosition(boxx + 2, boxy + boxheight - 2);
            Console.Write($"Press escape to leave {dialogue.ToLower()}.");
            Console.SetCursorPosition(boxwidth + boxx - 10, boxy + boxheight - 2);
            Console.Write($"Page {BOOKOFMONSTERSPAGE + 1}/{Math.Ceiling((double)NUMBEROFENTRIESINBOOKOFMONSTERS / 6)}");
            do
            {
                ConsoleKeyInfo key = Console.ReadKey(true);
                switch (key.Key)
                {
                    case ConsoleKey.W:
                        choice = (choice - 1 + options.GetLength(0)) % options.GetLength(0);
                        DrawMenu(choice, options, menutop, menuleft, boxwidth - 4);
                        break;

                    case ConsoleKey.S:
                        choice = (choice + 1) % options.GetLength(0);
                        DrawMenu(choice, options, menutop, menuleft, boxwidth - 4);
                        break;

                    case ConsoleKey.Enter:
                        return choice;

                    case ConsoleKey.Escape:
                        running = false;
                        return -2;
                    case ConsoleKey.D:
                        GenerateBookOfMonstersPage();
                        BOOKOFMONSTERSPAGE++;
                        return -3;
                    case ConsoleKey.A:
                        GenerateBookOfMonstersPage();
                        BOOKOFMONSTERSPAGE--;
                        return -3;
                }
            } while (running);

            return -1;
        }
