        static void GenerateBookOfMonstersPage()
        {
            int i = BOOKOFMONSTERSPAGE * 6;
            int temp = i;
            do
            {
                if (NUMBEROFENTRIESINBOOKOFMONSTERS - i <= -6)
                {
                    BOOKOFMONSTERSPAGE -= BOOKOFMONSTERSPAGE;
                    break;
                }
                if (BOOKOFMONSTERSPAGE < 0)
                {
                    BOOKOFMONSTERSPAGE = (int)Math.Ceiling((double)NUMBEROFENTRIESINBOOKOFMONSTERS / 6) - 1;
                    break;
                }
                if (NUMBEROFENTRIESINBOOKOFMONSTERS - i <= 0)
                {
                    BOOKOFMONSTERS[i - temp, 0] = "";
                    BOOKOFMONSTERS[i - temp, 1] = "Empty";
                }
                else
                {
                    try
                    {
                        BOOKOFMONSTERS[i - temp, 0] = BOOKOFMONSTERSMONSTERS[i];
                        BOOKOFMONSTERS[i - temp, 1] = BOOKOFMONSTERSSTATES[i];
                    }
                    catch (ArgumentOutOfRangeException)
                    {

                    }
                }
                i++;
            } while (i % 6 != 0);
        }
