        static int Battle(int enemyhealth, int enemymaxhealth, double difficulty, string enemyname, string enemysprite, int x, int y)
        {
            int enemyattack;
            int attack = 0;
            int item = 0;
            int choice;
            int criticalhit;
            string[,] options =
            {
        {"", "Fight"},
        {"", "Item"},
        {"", "Mercy"}
            };
            while (true)
            {
                DisplayScene(LoadScene(enemysprite), x, y);
                DisplayBossBar(enemyname, enemyhealth, enemymaxhealth, 0);
                DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                choice = DisplayTimedMenu(options, "Your move", X, Y, W, H, 5);
                if (rng.NextDouble() * difficulty <= 0.1)
                {
                    criticalhit = rng.Next(5, 11);
                }
                else
                {
                    criticalhit = 0;
                }
                switch (choice)
                {
                    case 0:
                        switch (DisplayReactionMenu("Your move", X, Y, W, H, 10))
                        {
                            case 4:
                                attack = 0;
                                break;
                            case 3:
                                attack = 1;
                                break;
                            case 2:
                                attack = 2;
                                break;
                            case 1:
                                attack = 3;
                                break;
                            case 0:
                                attack = 4;
                                break;
                        }
                        if (criticalhit != 0)
                        {
                            DisplayVFX("CRITICAL HIT!");
                        }
                        enemyhealth -= attack * 3 + criticalhit;
                        if (enemyhealth <= 0)
                        {
                            enemyhealth = 0;
                            DisplayBossBar(enemyname, enemyhealth, enemymaxhealth, 0);
                            DisplayItemCollectionDialogue($"You killed x1 {enemyname.ToUpper()}");
                            if (MODE == "ADVENTURE")
                            {
                                AddEntryToBookOfMonsters($"{enemyname.ToUpper()}", "Killed");
                                ADVENTUREMODEKILLS++;
                            }
                            else
                            {
                                ARCADEMODEKILLS++;
                            }
                            return 0;
                        }
                        break;
                    case 1:
                        item = Inventory();
                        if (item != -1)
                        {
                            switch (INVENTORY[item, 1])
                            {
                                case "Book of Monsters":
                                    BookOfMonsters();
                                    break;
                                case "Magic Staff":
                                    if (MANA >= 10)
                                    {
                                        attack = rng.Next(20, 51) + criticalhit;
                                        if (enemyhealth - attack <= 0)
                                        {
                                            DisplayVFX("ENEMY HEALTH TOO LOW!");
                                        }
                                        else
                                        {
                                            DecrementMana(rng.Next(10, 31));
                                            DisplayVFX("MANA ATTACK SUCCESSFUL!");
                                            enemyhealth -= attack;
                                        }
                                    }
                                    else
                                    {
                                        DisplayVFX("NOT ENOUGH MANA!");
                                    }
                                    break;
                                case "Mirror":
                                    if (enemyname != "GUIDE")
                                    {
                                        DisplayDialogue($"The {enemyname.ToUpper()} looks at itself in the Mirror.", X, Y, W, H);
                                        DisplayDialogue($"{enemyname.ToUpper()} - Who's that handsome {enemyname.ToUpper()}?", X, Y, W, H);
                                        AddEntryToBookOfMonsters($"{enemyname.ToUpper()}", "Spared");
                                        DisplayVFX($"SPARED {enemyname.ToUpper()}!");
                                        IncrementMana();
                                        return 1;
                                    }
                                    break;
                                case "Bread":
                                    HEALTH += 30;
                                    if (HEALTH > 100)
                                    {
                                        HEALTH = 100;
                                    }
                                    DisplayVFX("YOU HEALED BY EATING 1x BREAD!");
                                    INVENTORY[item, 0] = "";
                                    INVENTORY[item, 1] = "Empty";
                                    break;
                            }
                        }
                        break;
                    case 2:
                        switch (difficulty)
                        {
                            case 1:
                                AddEntryToBookOfMonsters($"{enemyname.ToUpper()}", "Spared");
                                DisplayVFX($"SPARED {enemyname.ToUpper()}!");
                                return 1;
                            case 2:
                                if (rng.NextDouble() <= 0.5)
                                {
                                    AddEntryToBookOfMonsters($"{enemyname.ToUpper()}", "Spared");
                                    DisplayVFX($"SPARED {enemyname.ToUpper()}!");
                                    return 1;
                                }
                                else
                                {
                                    DisplayVFX($"FAILED TO SHOW MERCY TO {enemyname.ToUpper()}!");
                                    break;
                                }
                            case 3:
                                if (rng.NextDouble() <= 0.25)
                                {
                                    AddEntryToBookOfMonsters($"{enemyname.ToUpper()}", "Spared");
                                    DisplayVFX($"SPARED {enemyname.ToUpper()}!");
                                    return 1;
                                }
                                else
                                {
                                    DisplayVFX($"FAILED TO SHOW MERCY TO {enemyname.ToUpper()}!");
                                    break;
                                }
                            case 4:
                                if (rng.NextDouble() <= 0.1)
                                {
                                    AddEntryToBookOfMonsters($"{enemyname.ToUpper()}", "Spared");
                                    DisplayVFX($"SPARED {enemyname.ToUpper()}!");
                                    return 1;
                                }
                                else
                                {
                                    DisplayDialogue($"Failed to show Mercy to {enemyname.ToUpper()}!", X, Y, W, H);
                                    DisplayVFX($"FAILED TO SHOW MERCY TO {enemyname.ToUpper()}!");
                                    break;
                                }
                        }
                        break;
                    case -1:
                        HEALTH -= 10;
                        DisplayVFX("YOU TOOK TOO LONG TO MAKE A DESICION!");
                        break;
                }
                DisplayBossBar(enemyname, enemyhealth, enemymaxhealth, 0);
                DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                if (rng.NextDouble() * difficulty <= 0.05)
                {
                    criticalhit = rng.Next(5, 11);
                }
                else
                {
                    criticalhit = 0;
                }
                enemyattack = rng.Next(0, 4);
                Console.Clear();
                switch (enemyattack)
                {
                    case 0:
                        DisplayScene(LoadScene(enemysprite), x, y);
                        DisplayBossBar(enemyname, enemyhealth, enemymaxhealth, 0);
                        DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                        HEALTH += BouncyBulletGame(X, Y, W, H, 5) * rng.Next(5, 11) + criticalhit;
                        break;
                    case 1:
                        DisplayScene(LoadScene(enemysprite), x, y);
                        DisplayBossBar(enemyname, enemyhealth, enemymaxhealth, 0);
                        DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                        HEALTH += DinoGame(X, Y, W, H, 25, 5) * rng.Next(5, 11) + criticalhit;
                        break;
                    case 2:
                        DisplayScene(LoadScene(enemysprite), x, y);
                        DisplayBossBar(enemyname, enemyhealth, enemymaxhealth, 0);
                        DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                        HEALTH += WaveGame(X, Y, W, H, 10, 5) * rng.Next(5, 11) + criticalhit;
                        break;
                    case 3:
                        DisplayScene(LoadScene(enemysprite), x, y);
                        DisplayBossBar(enemyname, enemyhealth, enemymaxhealth, 0);
                        DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                        HEALTH += BlasterDodgemsGame(X, Y, W, H, 5) * rng.Next(5, 11) + criticalhit;
                        break;
                }
                if (HEALTH < 1)
                {
                    return -1;
                }
                Console.Clear();
                DisplayScene(LoadScene(enemysprite), x, y);
                DisplayBossBar(enemyname, enemyhealth, enemymaxhealth, 0);
                DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
            }
        }
        static void AddItemToInventory(string itemname, string count)
        {
            INVENTORY[NUMBEROFITEMSININVENTORY, 0] = count;
            INVENTORY[NUMBEROFITEMSININVENTORY, 1] = itemname;
            NUMBEROFITEMSININVENTORY++;
