        static int BattleEnchantedBunny(int enemyhealth, int enemymaxhealth, double difficulty, string enemyname, string enemysprite, int x, int y)
        {
            PlayMusicLooping("Battle_1.wav");
            const int MAXHEALTH = 100;
            int choice;
