        static void DisplayItemCollectionDialogue(string dialogue)
        {
            int x = X + 2;
            int y = Y + 1;
            Console.ForegroundColor = ConsoleColor.DarkBlue;
            Console.SetCursorPosition(X, Y);
            Console.Write("╔" + new string('═', W - 2) + "╗");
            for (int i = 1; i < H - 1; i++)
            {
                Console.SetCursorPosition(X, Y + i);
                Console.Write("║" + new string(' ', W - 2) + "║");
            }
            Console.SetCursorPosition(X, Y + H - 1);
            Console.Write("╚" + new string('═', W - 2) + "╝");
            Console.ResetColor();
            for (int i = 0; i < dialogue.Length; i++)
            {
                Console.SetCursorPosition(x, y);
                Console.Write(dialogue[i]);
                if ((i + 1) % (W - 4) == 0)
                {
                    y++;
                    x = X + 2;
                }
                else
                {
                    x++;
                }
                Console.ResetColor();
                Thread.Sleep(5);
            }
            Thread.Sleep(500);
        }
        static void IncrementMana()
        {
            string dialogue;
            if ((MANA + 10) <= MAXMANA)
            {
                dialogue = "You collected x10 ☆ Mana.";
                MANA += 10;
            }
            else
            {
                int manacollected = Math.Abs((MANA + 10) - MAXMANA);
                dialogue = $"You collected x{manacollected} ☆ Mana";
                MANA = MAXMANA;
            }
            PlayMusic("Collect_Mana.wav");
            DisplayItemCollectionDialogue(dialogue);
            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
        }
        static void DecrementMana(int count)
        {
            MANA -= count;
            if (MANA <= 0)
            {
                MANA = 0;
            }
            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
        }
        static string SaveScene(int[,] canvas)
        {
            string data = "";
            for (int y = 0; y < canvas.GetLength(1); y++)
            {
                for (int x = 0; x < canvas.GetLength(0); x++)
                {
                    data += canvas[x, y];
                    if (x < canvas.GetLength(0) - 1) data += "x";
                }
                data += "y";
            }
            return data;
        }
