        static void SpriteEditor()
        {
            const int canvaswidth = 84;
            const int canvasheight = 44;
            const int W = 50;
            const int H = 15;
            const int X = (((canvaswidth) - W) / 2);
            const int Y = canvasheight - H;
            int x = canvaswidth / 2;
            int y = canvasheight / 2;
            bool pendown = false;
            int[,] canvas = new int[canvaswidth, canvasheight];
            int colour = 15;
            const int boxx = X + W / 4;
            const int boxy = Y - 6;
            const int width = 25;
            const int height = 7;
            bool running = true;
            DrawEditorUI(canvaswidth, colour);
            DrawMenuBox(W, H, X, Y);
            Console.ForegroundColor = ConsoleColor.DarkGray;
            DrawMenuBox(width + 1, height, boxx, boxy);
            while (running)
            {
                if (Console.KeyAvailable)
                {
                    ConsoleKeyInfo key = Console.ReadKey(true);
                    switch (key.Key)
                    {
                        case ConsoleKey.UpArrow:
                            --y;
                            break;
                        case ConsoleKey.DownArrow:
                            ++y;
                            break;
                        case ConsoleKey.LeftArrow:
                            --x;
                            break;
                        case ConsoleKey.RightArrow:
                            ++x;
                            break;
                        case ConsoleKey.Tab:
                            if (pendown == false)
                            {
                                pendown = true;
                            }
                            else
                            {
                                pendown = false;
                            }
                            break;
                        case ConsoleKey.Enter:
                            Console.SetCursorPosition(canvaswidth + 5, 26);
                            Console.ForegroundColor = ConsoleColor.White;
                            Console.Write("Enter colour (0-15): ");
                            colour = int.Parse(Console.ReadLine());
                            Console.ForegroundColor = (ConsoleColor)colour;
                            DrawEditorUI(canvaswidth, colour);
                            Console.SetCursorPosition(canvaswidth + 5, 26);
                            Console.Write("                                          ");
                            break;
                        case ConsoleKey.C:
                            Console.Clear();
                            Console.SetCursorPosition(0, 0);
                            DrawEditorUI(canvaswidth, colour);
                            DrawMenuBox(W, H, X, Y);
                            Console.ForegroundColor = ConsoleColor.DarkGray;
                            DrawMenuBox(width + 1, height, boxx, boxy);
                            x = canvaswidth / 2;
                            y = canvasheight / 2;
                            break;
                        case ConsoleKey.S:
                            Console.SetCursorPosition(canvaswidth + 5, 26);
                            Console.ForegroundColor = ConsoleColor.White;
                            Console.Write("Enter name of File to Save to (do not include .txt): ");
                            File.WriteAllText($"{Console.ReadLine()}.txt", SaveScene(canvas));
                            Console.SetCursorPosition(canvaswidth + 5, 26);
                            Console.Write("                                          ");
                            pendown = false;
                            break;
                        case ConsoleKey.L:
                            Console.SetCursorPosition(canvaswidth + 5, 26);
                            Console.ForegroundColor = ConsoleColor.White;
                            Console.Write("Enter name of File to Load from (do not include .txt): ");
                            canvas = LoadScene(File.ReadAllText($"{Console.ReadLine()}.txt"));
                            Console.SetCursorPosition(canvaswidth + 5, 26);
                            Console.Write("                                          ");
                            DisplayScene(canvas, 0, 0);
                            DrawEditorUI(canvaswidth, colour);
                            DrawMenuBox(W, H, X, Y);
                            Console.ForegroundColor = ConsoleColor.DarkGray;
                            DrawMenuBox(width + 1, height, boxx, boxy);
                            break;
                        case ConsoleKey.X:
                            running = false;
                            break;
                    }
                    if (x >= canvaswidth - 1)
                    {
                        x = canvaswidth - 1;
                    }
                    if (y >= canvasheight - 1)
                    {
                        y = canvasheight - 1;
                    }
                    if (x <= 0)
                    {
                        x = 0;
                    }
                    if (y <= 0)
                    {
                        y = 0;
                    }

                    Console.SetCursorPosition(x, y);
                    if (pendown == true)
                    {
                        canvas[x, y] = colour;
                        Console.Write("█");
                    }

                }
            }
        }
        static string GenerateSaveCode()
        {
            string savecode = string.Empty;
            if (ARCADEMODEDEATHS != 0)
            {
                ARCADEMODEKD = ARCADEMODEKILLS / ARCADEMODEDEATHS;
            }
            else
            {
                ARCADEMODEKD = 0;
            }
            if (ADVENTUREMODEDEATHS != 0)
            {
                ADVENTUREMODEKD = ADVENTUREMODEKILLS / ADVENTUREMODEDEATHS;
            }
            else
            {
                ADVENTUREMODEKD = 0;
            }
            savecode += $"{VERSION},";
            savecode += $"{PLAYERNAME},";
            savecode += $"{ADVENTUREMODEDEATHS},";
            savecode += $"{ADVENTUREMODEKD},";
            savecode += $"{ADVENTUREMODEKILLS},";
            if (ADVENTUREMODEPB != null)
            {
                savecode += $"{ADVENTUREMODEPB},";
            }
            else
            {
                savecode += "null,";
            }
            savecode += $"{ADVENTUREMODERUNS},";
            savecode += $"{ARCADEMODEDEATHS},";
            savecode += $"{ARCADEMODEKD},";
            savecode += $"{ARCADEMODEKILLS},";
            savecode += $"{ARCADEMODEMAXWINSTREAK},";
            savecode += $"{ARCADEMODERUNS},";
            savecode += $"{ARCADEMODEWINSTREAK},";
            savecode += $"{TIME}";
            return savecode;
        }
        static void SaveGame()
        {
            Console.Clear();
            File.WriteAllText("Savecode.txt", GenerateSaveCode());
            DisplayVFX("Saved Progress to Savecode.txt");
        }
        static void LoadGame()
        {
            string savecode;
            string[,] options =
            {
                {"", "Load from local save"},
                {"", "Load from savecode"}
            };
            int choice = DisplayMenu(options, "Save/Load", X, Y, W, H);
            switch (choice)
            {
                case 0:
                    Console.SetCursorPosition(X + 2, Y + 3);
                    Console.Write("Loading from Savecode.txt...");
                    Thread.Sleep(50);
                    savecode = File.ReadAllText("Savecode.txt");
                    LoadSavecode(savecode);
                    break;
                case 1:
                    Console.SetCursorPosition(X + 2, Y + 2);
                    Console.Write("Enter savecode: ");
                    savecode = Console.ReadLine();
                    Console.SetCursorPosition(X + 2, Y + 3);
                    Console.Write("Loading from savecode...");
                    Thread.Sleep(50);
                    LoadSavecode(savecode);
                    break;
            }
        }
        static void LoadSavecode(string savecode)
        {
            string[] data = savecode.Split(',');
            if (data.Length < 14)
            {
                Console.WriteLine("Invalid savecode");
                return;
            }

            int i = 0;
            i++;
            PLAYERNAME = data[i++];
            ADVENTUREMODEDEATHS = int.Parse(data[i++]);
            ADVENTUREMODEKD = double.Parse(data[i++]);
            ADVENTUREMODEKILLS = int.Parse(data[i++]);
            string temp = data[i++];
            if (temp == "null" || temp == "")
            {
                ADVENTUREMODEPB = 0;
            }
            else
            {
                ADVENTUREMODEPB = int.Parse(temp);
            }
            ADVENTUREMODERUNS = int.Parse(data[i++]);
            ARCADEMODEDEATHS = int.Parse(data[i++]);
            ARCADEMODEKD = double.Parse(data[i++]);
            ARCADEMODEKILLS = int.Parse(data[i++]);
            ARCADEMODEMAXWINSTREAK = int.Parse(data[i++]);
            ARCADEMODERUNS = int.Parse(data[i++]);
            ARCADEMODEWINSTREAK = int.Parse(data[i++]);
            TIME = long.Parse(data[i++]);

            if (ARCADEMODEDEATHS != 0)
            {
                ARCADEMODEKD = (double)ARCADEMODEKILLS / (double)ARCADEMODEDEATHS;
            }
            else
            {
                ARCADEMODEKD = 0;
            }
            if (ADVENTUREMODEDEATHS != 0)
            {
                ADVENTUREMODEKD = (double)ADVENTUREMODEKILLS / (double)ADVENTUREMODEDEATHS;
            }
            else
            {
                ADVENTUREMODEKD = 0;
            }
            Console.WriteLine("Sucesfully loaded savecode!");
        }
        static void SaveLoadMenu()
        {
            string[,] options =
            {
                {"", "Save Progress"},
                {"", "Load Progress"}
            };
            int choice = DisplayMenu(options, "Save/Load", X, Y, W, H);
            switch (choice)
            {
                case 0:
                    SaveGame();
                    break;
                case 1:
                    LoadGame();
                    break;
            }
        }
        static int DisplayStartMenu(string[,] options, string dialogue, int boxx, int boxy, int boxwidth, int boxheight)
        {
            FadeInScene(LoadScene(""), X1, Y1);
            int choice = 0;
            bool running = true;
            DrawMenuBox(boxwidth, boxheight, boxx, boxy);
            Console.SetCursorPosition(boxx + 2, boxy + 1);
            Console.WriteLine(dialogue);
            int menuTop = Console.CursorTop + 1;
            int menuLeft = boxx + 3;
            bool blink = true;
            int blinktimer = 0;
            int tick = 0;
            DrawMenuBox(boxwidth, boxheight, boxx, boxy);
            DrawMenu(choice, options, menuTop, menuLeft, boxwidth - 4);
            do
            {
                Console.ForegroundColor = ConsoleColor.White;
                Console.SetCursorPosition(0, CONSOLEHEIGHT - 1);
                Console.Write($"v{VERSION}_TheBookofMonsters");
                tick++;
                blinktimer++;
                Console.ForegroundColor = ConsoleColor.White;
                if (Console.KeyAvailable)
                {
                    ConsoleKeyInfo key = Console.ReadKey(true);
                    switch (key.Key)
                    {
                        case ConsoleKey.W:
                            choice = (choice - 1 + options.GetLength(0)) % options.GetLength(0);
                            DrawMenuBox(boxwidth, boxheight, boxx, boxy);
                            DrawMenu(choice, options, menuTop, menuLeft, boxwidth - 4);
                            break;

                        case ConsoleKey.S:
                            choice = (choice + 1) % options.GetLength(0);
                            DrawMenuBox(boxwidth, boxheight, boxx, boxy);
                            DrawMenu(choice, options, menuTop, menuLeft, boxwidth - 4);
                            break;

                        case ConsoleKey.Enter:
                            FadeOutScene(LoadScene(""), X1, Y1);
                            return choice;

                        case ConsoleKey.Escape:
                            running = false;
                            return -1;
                    }
                }
                if ((Math.Abs(tick) % 20000 == 0 && rng.NextDouble() <= 0.3) || (blink && blinktimer % 10000 == 0))
                {
                    if (blink)
                    {
                        Console.SetCursorPosition(X1 + 80, Y1 + 10);
                        Console.Write("  ");
                        Console.SetCursorPosition(X1 + 88, Y1 + 10);
                        Console.Write("  ");
                        blink = false;
                        blinktimer = 0;
                    }
                    else
                    {
                        Console.ForegroundColor = ConsoleColor.DarkRed;
                        Console.SetCursorPosition(X1 + 80, Y1 + 10);
                        Console.Write("██");
                        Console.SetCursorPosition(X1 + 88, Y1 + 10);
                        Console.Write("██");
                        blink = true;
                        blinktimer = 0;
                    }
                }
            } while (running);

            return -1;
        }
