                    DisplayDialogue("Story & design:                                                                                 Inspired by Undertale, Legends of Zelda", X, Y, W, H);
                    DisplayDialogue("Music & SFX:                                                                                    Chips n' cellos, John williams, Kevin macleod, Sans, opengameart.org", X, Y, W, H);
                    DisplayDialogue("Playtesting:                                                                                    Benjamin Fernandes-Berger, Kamil Suski", X, Y, W, H);
                    DisplayDialogue("Honourable mentions:                                                                            Stack overflow, C#, .NET framework 4.7.2", X, Y, W, H);
