        static void Start()
        {
            int menuchoice;
            InitialiseGame();
            AskUsername();
            do
            {

                PlayMusicLooping("Theme.wav");
                do
                {
                    menuchoice = StartMenu();
                } while (menuchoice == -1);
                PlayMusic("Click.wav");
                switch (menuchoice)
                {
                    case 0:
                        try
                        {
                            PlayGameAdventureMode();
                        }
                        catch (AdventureModeDeath)
                        {
                            InitialiseVariables();
                        }
                        break;
                    case 1:
                        try
                        {
                            PlayGameArcadeMode();
                        }
                        catch (ArcadeModeDeath)
                        {
                            InitialiseVariables();
                        }
                        break;
                }
            } while (true);
        }
