        static void Prologue()
        {
            DisplayVFX("CHAPTER I - The Village");
            DrawMenuBox(W, H, X, Y);
            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
            DisplayDialogue("You awaken in bed in a quiet village. Lanterns sway. The air smells faintly of damp earth.", X, Y, W, H);
            DisplayDialogue("All is still — too still.", X, Y, W, H);
            DisplayDialogue("You turn around in bed to see an old man, with a beaming wide smile looking at you", X, Y, W, H);
            DisplayScene(LoadScene(""), X1, Y1);
            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
            DrawMenuBox(W, H, X, Y);
