        static void GuideTraining()
        {
            SoundPlayer SFX = new SoundPlayer("Collect_Mana.wav");
            DisplayVFX("CHAPTER II - Training");
            DrawMenuBox(W, H, X, Y);
            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
            bool running = true;
            DisplayScene(LoadScene(""), X1, Y1);
            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
            DrawMenuBox(W, H, X, Y);
            DisplayDialogue("A wooden training dummy stands in the center of the room. It looks sturdy, but not dangerous.", X, Y, W, H);
            DisplayVoicedDialogue($"GUIDE - This is your first lesson, {PLAYERNAME}. You will learn how to attack, how to spare,   and how to feel Mana flow.", X, Y, W, H);
            PlayMusicLooping("Battle_1.wav");
            {
                string[,] options =
                {
                    {"", "Fight"},
                    {"", "Item"},
                    {"", "Mercy"}
                };
                while (running)
                {
                    DisplayBossBar("TRAINING DUMMY", 1, 1, 0);
                    DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                    switch (DisplayMenu(options, "Your move", X, Y, W, H))
                    {
                        case 0:
                            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                            DisplayDialogue("You swing at the TRAINING DUMMY. It wobbles and creaks under your strike.", X, Y, W, H);
                            PlayMusic("Click.wav");
                            DisplayScene(LoadScene(""), X1, Y1);
                            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                            DrawMenuBox(W, H, X, Y);
                            DisplayVoicedDialogue($"GUIDE - Good! Feel the force, {PLAYERNAME}. That energy you generated... that is Mana.", X, Y, W, H);
                            DisplayDialogue("Your hands tingle as a small Mana Star floats toward you.", X, Y, W, H);
                            IncrementMana();
                            running = false;
                            break;
                        case 1:
                            Inventory();
                            break;
                        case 2:
                            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                            DisplayDialogue("You step back and bow to the dummy, letting it stand untouched.", X, Y, W, H);
                            PlayMusic("Click.wav");
                            DisplayScene(LoadScene(""), X1, Y1);
                            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                            DrawMenuBox(W, H, X, Y);
                            DisplayVoicedDialogue($"GUIDE - Excellent. Mercy requires awareness and patience, {PLAYERNAME}.", X, Y, W, H);
                            DisplayDialogue("Even without striking, you feel a spark of Mana rise in your chest.", X, Y, W, H);
                            IncrementMana();
                            running = false;
                            break;
                    }
                }

            }
            DisplayVoicedDialogue("GUIDE - Now that you’ve felt mana, it’s time to learn to wield it. Take this staff.", X, Y, W, H);
            DisplayDialogue("The staff glows faintly as you hold it, humming in tune with your heartbeat.", X, Y, W, H);
            DisplayItemCollectionDialogue("You collected x1 ☆ Magic Staff.");
            AddItemToInventory("Magic Staff", "1");
            DisplayVoicedDialogue("GUIDE - To use mana, use the Magic Staff item in your inventory.", X, Y, W, H);
            DisplayVoicedDialogue("GUIDE - Take this compass, it will guide you to the castle.", X, Y, W, H);
            DisplayVoicedDialogue($"{PLAYERNAME} - What good is this compass if I don't have a map to accompany it?", X, Y, W, H);
            DisplayVoicedDialogue("The GUIDE chortles.", X, Y, W, H);
            DisplayVoicedDialogue("GUIDE - It's a *magic* compass, the rules don't apply for it.", X, Y, W, H);
            DisplayItemCollectionDialogue("You collected x1 ☆ Magic Compass.");
            AddItemToInventory("Magic Compass", "1");
            DisplayVoicedDialogue("GUIDE - Take this bread, use it to heal when you are weak.", X, Y, W, H);
            DisplayItemCollectionDialogue("You collected x1 ☆ Bread.");
            AddItemToInventory("Bread", "1");
            DisplayVoicedDialogue("GUIDE - Take this Mirror, in it, you may show others their true self.", X, Y, W, H);
            DisplayItemCollectionDialogue("You collected x1 ☆ Mirror.");
            AddItemToInventory("Mirror", "1");
            DisplayVoicedDialogue("GUIDE - Finally, take this mana, to power your staff.", X, Y, W, H);
            PlayMusic("Collect_Mana.wav");
            DisplayItemCollectionDialogue("You collected x50 ☆ Mana.");
            MANA += 50;
            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
            DisplayVoicedDialogue($"{PLAYERNAME} - Is that all?", X, Y, W, H);
            DisplayVoicedDialogue("GUIDE - Yes.", X, Y, W, H);
            DisplayVoicedDialogue($"GUIDE - Remember, {PLAYERNAME}, your choices shape your path. Attack when needed... show mercy when possible.", X, Y, W, H);
            DisplayVoicedDialogue("GUIDE - Once ready, the World awaits beyond this cottage. Your real journey begins there.", X, Y, W, H);
            Console.Clear();
            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
            DisplayDialogue("You leave the village, en route to the Castle.", X, Y, W, H);
            Crossroads();
        }
