        static void CastleEntrance()
        {
            DisplayVFX("CHAPTER V - The Castle");
            DrawMenuBox(W, H, X, Y);
            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
            DisplayDialogue("The castle gates loom before you, their iron bars twisted like roots clawing at the sky.", X, Y, W, H);
            DisplayDialogue("Torches flicker weakly along the walls, casting long shadows that seem to breathe.", X, Y, W, H);
            DisplayDialogue("The air hums faintly — a strange, familiar energy fills your chest.", X, Y, W, H);
            DisplayVoicedDialogue($"{PLAYERNAME} - This is it... The Castle...", X, Y, W, H);
            DisplayScene(LoadScene(""), X1, Y1);
            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
            DrawMenuBox(W, H, X, Y);
            DisplayDialogue("You step up to the castle gates. Two guards in black lacquered armor stand sentinel beneath a   banner of a broken crown.", X, Y, W, H);
            DisplayVoicedDialogue("Their visors are blank mirrors. Their posture is perfect — trained, practiced, patient.", X, Y, W, H);
            DisplayVoicedDialogue("GUARD 1 - Halt. State your business. No one passes without the KING'S leave.", X, Y, W, H);
            DisplayVoicedDialogue("GUARD 2 - If you carry blades, we shall take them. If you carry lies, we shall hear them.", X, Y, W, H);

            {
                string[,] options =
                {
                    {"", "Trick"},
                    {"", "Fight"}
                };
                switch (DisplayMenuWithSound(options, "GUARD 2 - If you carry blades, we shall take them. If you carry lies, we shall hear them.", X, Y, W, H))
                {
                    case 0:
                        DisplayDialogue("You step forward with calm.", X, Y, W, H);
                        DisplayVoicedDialogue($"{PLAYERNAME} - I'm a...", X, Y, W, H);
                        DisplayVoicedDialogue($"{PLAYERNAME} - Jester...", X, Y, W, H);
                        DisplayVoicedDialogue($"{PLAYERNAME} - For the KING, of course...", X, Y, W, H);
                        DisplayDialogue("The guards exchange a micro-glance.", X, Y, W, H);
                        DisplayVoicedDialogue("GUARD 1 - A jester? You don't look that funny to me.", X, Y, W, H);
                        DisplayVoicedDialogue("GUARD 2 - The KING has a really bad sense of humor, remember?", X, Y, W, H);
                        DisplayDialogue("A long, tense beat. The guards confer in whispers you do not hear.", X, Y, W, H);
                        DisplayVoicedDialogue("GUARD 1 - Very well. Move along. But know this — the KING'S patience is thin with you jesters.", X, Y, W, H);
                        DisplayDialogue("They step aside, rigid and suspicious, but do not stop you. You slip through the gates into thecastle's yard.", X, Y, W, H);
                        DisplayDialogue("Whether you truly fooled them or luck favoured you, the entrance remains unbloodied.", X, Y, W, H);
                        break;
                    case 1:
                        DisplayDialogue("You curl your hands up into a fist and scowl at the GUARDS.", X, Y, W, H);
                        DisplayVoicedDialogue("GUARD 1 - So be it. ", X, Y, W, H);
                        DisplayDialogue("He advances with the speed of a well-oiled machine.", X, Y, W, H);
                        FightGuard();
                        DisplayVoicedDialogue("GUARD 1 - Order... must... be... restored...", X, Y, W, H);
                        DisplayDialogue("GUARD 2 staggers back, eyes flicking to his fallen comrade, then turns and runs, helmet clankingthrough the gate as he flees in panic.", X, Y, W, H);
                        DisplayDialogue("The path into the castle lies open, though the sound of distant marching drums suggests more    danger ahead.", X, Y, W, H);

                        break;
                }
            }
            DisplayDialogue("As you pass beneath the vaulted arch, the castle swallows you in shadow and echo.", X, Y, W, H);
            Castle();
        }
