        static void BattleGuidePhase2()
        {
            int choice;
            int criticalhit;
            int round = 0;
            string[,] options =
            {
        {"", "Fight"},
        {"", "Item"},
        {"", "Mercy"}
            };
            int[] guidemoves = { 2, 3, 2, 2, 3, 3, 3, 4, 1 };
            bool running = true;
            while (running)
            {
                round++;
                DisplayScene(LoadScene(""), X1, Y1);
                DisplayBossBar("GUIDE", 1, 1, 0);
                DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                if (HEALTH <= 0)
                {
                    DisplayDialogue("The GUIDE swiftly and brutally ends the fight, and your journey.", X, Y, W, H);
                    ShowDeathMessage("You were slain by The GUIDE!");
                    break;
                }
                switch (round)
                {
                    case 3:
                        DisplayUnskippableDialogue("GUIDE - It's kill or be killed here, don't you understand?", X, Y, W, H);
                        break;
                    case 7:
                        DisplayUnskippableDialogue("GUIDE - Do you think this ends with me? No. It ends with whoever sits on that throne.", X, Y, W, H);
                        break;
                    case 9:
                        DisplayUnskippableDialogue("GUIDE - I taught you the songs of mercy. Why do you hum the other tune?", X, Y, W, H);
                        break;
                }
                choice = DisplayTimedMenu(options, "Your move", X, Y, W, H, 5);
                switch (choice)
                {
                    case 0:
                        DisplayReactionMenu("Your move", X, Y, W, H, 10);
                        DisplayVFX("MISS!");
                        break;
                    case 1:
                        DisplayDialogue("You cannot use your inventory at this present moment in time.", X, Y, W, H);
                        break;
                    case 2:
                        DisplayUnskippableVoicedDialogue("GUIDE - You expect mercy? In this place?", X, Y, W, H);
                        DisplayDialogue("The GUIDE swiftly and brutally ends the fight, and your journey.", X, Y, W, H);
                        ShowDeathMessage("You were slain by The GUIDE!");
                        break;
                    case -1:
                        HEALTH -= 1;
                        DisplayVFX("YOU TOOK TOO LONG TO MAKE A DESICION!");
                        break;
                }
                DisplayBossBar("GUIDE", 1, 1, 0);
                DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                if (HEALTH < 1)
                {

                }
                if (rng.NextDouble() * 5 <= 0.05)
                {
                    criticalhit = rng.Next(5, 11);
                }
                else
                {
                    criticalhit = 0;
                }
                if (round == 10)
                {
                    running = false;
                    break;
                }
                switch (guidemoves[round - 1])
                {
                    case 1:
                        Console.Clear();
                        DisplayScene(LoadScene(""), X1, Y1);
                        DisplayBossBar("GUIDE", 1, 1, 0);
                        DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                        HEALTH += BouncyBulletGame(X, Y, W, H, 5) * 1;
                        break;
                    case 2:
                        Console.Clear();
                        DisplayScene(LoadScene(""), X1, Y1);
                        DisplayBossBar("GUIDE", 1, 1, 0);
                        DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                        HEALTH += DinoGame(X, Y, W, H, 25, 10) * 1;
                        break;
                    case 3:
                        Console.Clear();
                        DisplayScene(LoadScene(""), X1, Y1);
                        DisplayBossBar("GUIDE", 1, 1, 0);
                        DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                        HEALTH += WaveGame(X, Y, W, H, 10, 10) * 1;
                        break;
                    case 4:
                        Console.Clear();
                        DisplayScene(LoadScene(""), X1, Y1);
                        DisplayBossBar("GUIDE", 1, 1, 0);
                        DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                        HEALTH += BlasterDodgemsGame(X, Y, W, H, 3) * 1;
                        break;
                }
                DisplayBossBar("GUIDE", 1, 1, 0);
                DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
            }
            PlayMusic("Click.wav");
            DisplayUnskippableDialogue("With a final, powerful blow, The GUIDE strikes you down to your knees.", X, Y, W, H);
            DisplayUnskippableDialogue("As you collapse, something tumbles from your inventory — the Mirror. It spins on the floor and  you look at it, puzzled.", X, Y, W, H);
            DisplayUnskippableDialogue("The Mirror flashes. A faint warmth hums from it like a remembered song.", X, Y, W, H);
            DisplayUnskippableVoicedDialogue("GUIDE - You still carry that trinket?", X, Y, W, H);
            {
                string[,] yourchoice =
                {
                    {"", "Use Mirror"}
                };
                switch (DisplayTimedMenu(yourchoice, "GUIDE - You still carry that trinket?", X, Y, W, H, 3))
                {
                    case 0:
                        if (KINDNESSFACTOR >= 0)
                        {
                            DisplayUnskippableVoicedDialogue("GUIDE - For old times' sake, strike true. Or spare me— if you have the courage.", X, Y, W, H);
                            DisplayUnskippableDialogue("You raise the Mirror toward the GUIDE. The glass gleams in its' golden light.", X, Y, W, H);
                            DisplayUnskippableDialogue("In its surface, the GUIDE does not see a ruler, but a tired, weary, feeble old man, ridden with guilt over his past actions.", X, Y, W, H);
                            DisplayUnskippableDialogue("The Mirror displays countless faces of those long lost.", X, Y, W, H);
                            DisplayScene(LoadScene(""), X1, Y1);
                            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                            DrawMenuBox(W, H, X, Y);
                            DisplayUnskippableVoicedDialogue("GUIDE - I remember now. I loved them so badly, so I trapped them here as not to be alone.", X, Y, W, H);
                            DisplayUnskippableDialogue("The GUIDE staggers back, eyes filling with a sorrow so ancient it breaks him.", X, Y, W, H);
                            DisplayUnskippableVoicedDialogue("GUIDE - Teach me mercy.", X, Y, W, H);
                            DisplayUnskippableDialogue("Light pours from the Mirror.", X, Y, W, H);
                            DisplayUnskippableDialogue("The Mirror expands into a doorway of soft dawn, shimmering.", X, Y, W, H);
                            DisplayUnskippableVoicedDialogue($"GUIDE - Go, {PLAYERNAME}. Take back your destiny. The world will remember your sacrifice.", X, Y, W, H);
                            DisplayUnskippableDialogue("The GUIDE dissolves into thousands of butterflies, soaring around the Throne Room.", X, Y, W, H);
                            FadeOutScene(LoadScene(""), X1, Y1);
                            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                            DrawMenuBox(W, H, X, Y);
                            DisplayUnskippableDialogue("You realise that the Mirror *is* the portal home and you step through, with renouned confidence.", X, Y, W, H);
                            Epilogue(true);
                        }
                        else
                        {
                            DisplayUnskippableVoicedDialogue("GUIDE - For old times' sake, strike true. Or spare me— if you have the courage.", X, Y, W, H);
                            DisplayUnskippableDialogue("You hold the Mirror up with trembling fingers. The glass shows your face — but then it shifts.", X, Y, W, H);
                            DisplayUnskippableDialogue("In the Mirror, your reflection blurs, and for a heartbeat you see *his* face replace yours, the GUIDE'S weary smile sliding in and out of view.", X, Y, W, H);
                            DisplayUnskippableVoicedDialogue("GUIDE - At last. The mirror shows us both. You will sit where I sat, and I will be freed.", X, Y, W, H);
                            DisplayUnskippableVoicedDialogue("GUIDE - If I die, I will be free. ", X, Y, W, H);
                            DisplayUnskippableDialogue("He steps back, and with the same practiced motion he fought you with...", X, Y, W, H);
                            DisplayUnskippableDialogue("He brings the staff down upon himself in an act of terrible finality. The lights snuff out.", X, Y, W, H);
                            DisplayUnskippableDialogue("Light pours from the Mirror. The GUIDE dissolves into thousands of tiny bats and flutters aroundthe Throne Room, out of the Castle.", X, Y, W, H);
                            FadeOutScene(LoadScene(""), X1, Y1);
                            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
                            DrawMenuBox(W, H, X, Y);
                            Epilogue(false);

                        }
                        break;
                    case -1:
                        ShowDeathMessage("You were slain by The GUIDE whilst trying to get to the Mirror!");
                        break;
                }
            }
        }
        static void Epilogue(bool state)
        {
            DisplayVFX("Chapter VII - The Ending");
            DrawMenuBox(W, H, X, Y);
            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
            DisplayUnskippableDialogue("You open the Book of Monsters one last time....", X, Y, W, H);
            TIMER.Stop();
            PlayMusic("Clock.wav");
            switch (state)
            {
                case true:
                    BOOKOFMONSTERSPAGE = 0;
                    AddEntryToBookOfMonsters("Guide", "Freed");
                    AddEntryToBookOfMonsters($"{PLAYERNAME}", "Freed");
                    DisplayEpilogueBookOfMonsters(BOOKOFMONSTERS, "Book of Monsters", X, Y, W, H, true);
                    break;
                case false:
                    BOOKOFMONSTERSPAGE = 0;
                    AddEntryToBookOfMonsters("Guide", "Freed");
                    AddEntryToBookOfMonsters($"{PLAYERNAME}", "Trapped");
                    DisplayEpilogueBookOfMonsters(BOOKOFMONSTERS, "Book of Monsters", X, Y, W, H, false);
                    break;
            }
            Console.Clear();
            Thread.Sleep(500);
            PlayMusic("Click.wav");
            DisplayTier();
        }
        static void DisplayTier()
        {
            PlayMusic("Victory.wav");
            long elapsedmilliseconds = TIMER.ElapsedMilliseconds;
            TIME += (long)Math.Ceiling((double)elapsedmilliseconds / 60000);
            TimeSpan timespan = TIMER.Elapsed;
            string formattedtime = timespan.ToString(@"mm\:ss\.fff");
            DrawMenuBox(W, H, X, Y);
            DisplayVFX($"RUN TIME: {formattedtime}");
            if (elapsedmilliseconds <= 420000)
            {
                DisplayVFX("YOU GOT S TIER!");
            }
            else if (elapsedmilliseconds <= 450000)
            {
                DisplayVFX("YOU GOT A TIER!");
            }
            else if (elapsedmilliseconds <= 510000)
            {
                DisplayVFX("YOU GOT B TIER!");
            }
            else if (elapsedmilliseconds <= 540000)
            {
                DisplayVFX("YOU GOT C TIER!");
            }
            else if (elapsedmilliseconds <= 570000)
            {
                DisplayVFX("YOU GOT D TIER!");
            }
            else if (elapsedmilliseconds <= 600000)
            {
                DisplayVFX("YOU GOT E TIER!");
            }
            else
            {
                DisplayVFX("YOU GOT F TIER!");
            }
            DisplaySpecialVFX("Press any key to go back to the Start menu.");
        }
