            switch (Battle(25, 25, 5, "ROYAL GUARD", "", X1, Y1))
            {
                case -1:
                    PlayMusic("Click.wav");
                    ShowDeathMessage("You slain by the KING'S ROYAL GUARD!");
                    break;
                case 0:
                    --KINDNESSFACTOR;
                    PlayMusic("Click.wav");
                    DisplayDialogue("You strike quickly and manage to the GUARD with a skillful blow!", X, Y, W, H);
                    DisplayDialogue("A Mana Star floats gently toward you, pulsing with energy.", X, Y, W, H);
                    IncrementMana();
                    break;
            }
            Console.Clear();
            DisplayPlayerInfo(HEALTH, MAXHEALTH, MANA, MAXMANA, PLAYERNAME);
            DrawMenuBox(W, H, X, Y);
        }
        static void Main(string[] args)
        {
            Start();
        }
    }
